solution_code:
#include <iostream>

int main()
{
    int n{};
    std::cin >> n;

    std::cout << "int: " << sizeof(int) << " bytes\n";
    std::cout << "long long: " << sizeof(long long) << " bytes\n";
    std::cout << "value: " << static_cast<long long>(n) << "\n";

    return 0;
}

