solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    double result{ static_cast<double>(a) / b };

    std::cout << std::fixed << std::setprecision(2) << result << "\n";
    return 0;
}
